import UIKit
import Alamofire

class TradeViewController: UIViewController {
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var priceLabel: UILabel!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        fetchStockPrice(symbol: "AAPL")
    }
    
    @IBAction func executeTradeButtonTapped(_ sender: UIButton) {
        guard let symbol = stockSymbolTextField.text, let quantityString = quantityTextField.text,
              let quantity = Int(quantityString), quantity > 0 else {
            return
        }
        
        // Simulate trade execution
        executeTrade(symbol: symbol, quantity: quantity)
    }
    
    func fetchStockPrice(symbol: String) {
        let apiKey = "YOUR_API_KEY"
        let url = "https://api.example.com/stock/\(symbol)/price?key=\(apiKey)"
        
        Alamofire.request(url).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let price = value as? Double {
                    DispatchQueue.main.async {
                        self.priceLabel.text = "$\(String(format: "%.2f", price))"
                    }
                }
            case .failure(let error):
                print("Error fetching stock price: \(error)")
            }
        }
    }
    
    func executeTrade(symbol: String, quantity: Int) {
        let apiKey = "YOUR_API_KEY"
        let url = "https://api.example.com/executeTrade?symbol=\(symbol)&quantity=\(quantity)&key=\(apiKey)"
        
        Alamofire.request(url).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let message = value as? String {
                    DispatchQueue.main.async {
                        alert(message: message)
                    }
                }
            case .failure(let error):
                print("Error executing trade: \(error)")
            }
        }
    }
    
    func alert(message: String) {
        let alertController = UIAlertController(title: "Trade Status", message: message, preferredStyle: .alert)
        let okAction = UIAlertAction(title: "OK", style: .default, handler: nil)
        alertController.addAction(okAction)
        present(alertController, animated: true, completion: nil)
    }
}

extension TradeViewController {
    func setupUI() {
        // Custom UI setup
    }
    
    func handleAPIErrors(_ error: Error) {
        print("API Error: \(error.localizedDescription)")
    }
